import socket
import threading
import json

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_address = (host, port)
        self.players = []
        self.game_state = {}
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind(self.server_address)
        self.lock = threading.Lock()

    def start(self):
        print(f"Server started on {self.server_address}")
        while True:
            data, address = self.sock.recvfrom(4096)
            threading.Thread(target=self.handle_request, args=(data, address)).start()

    def handle_request(self, data, address):
        if data.decode() == "STATUS":
            self.send_status(address)

    def send_status(self, address):
        with self.lock:
            response = {
                'players': self.players,
                'game_state': self.game_state
            }
            response_data = json.dumps(response).encode()
            self.sock.sendto(response_data, address)

    def update_game_state(self, new_state):
        with self.lock:
            self.game_state.update(new_state)

    def add_player(self, player):
        with self.lock:
            self.players.append(player)

    def remove_player(self, player):
        with self.lock:
            self.players.remove(player)

if __name__ == "__main__":
    server = GameServer()
    server.start()